import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Sanitize and escape user input before using it in the HTML response
            String sanitizedUserName = Encode.forHtml(userName);

            String htmlResponse = "<h1>Welcome, " + sanitizedUserName + "!</h1>";

            System.out.println(htmlResponse);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
